import typing
from urllib.parse import parse_qs, unquote, urlencode as _urlencode, urlparse as _urlparse

import idna


# Simple type aliases to mimic the original module's expectations.
QueryParamTypes = typing.Union[dict, typing.List[typing.Tuple[str, typing.Any]], str, None]
RawURL = typing.Union[bytes, str]
URLTypes = typing.Union["URL", str]


def primitive_value_to_str(value: typing.Any) -> str:
    """
    Convert a primitive value to its string representation.

    This is a lightweight replacement for the original utility used in the
    source code. It handles None by returning an empty string and otherwise
    uses str().
    """
    if value is None:
        return ""
    return str(value)


class QueryParams:
    """
    A simple query-parameter container that preserves multiple values per key.

    It behaves much like a multi-dict, offering mapping-like operations.
    """

    def __init__(self, params: QueryParamTypes = None) -> None:
        """
        Initialize the QueryParams object.

        Accepts:
        - dict -> mapping of keys to values (values may be lists)
        - list of (key, value) tuples -> preserved order and duplicates
        - string -> a query string, parsed by parse_qs
        - None -> empty
        """
        self._store: typing.List[typing.Tuple[str, str]] = []

        if params is None:
            return

        if isinstance(params, str):
            # parse_qs returns lists of values per key
            parsed = parse_qs(params, keep_blank_values=True, strict_parsing=False)
            for key, values in parsed.items():
                for v in values:
                    self._store.append((key, v))
        elif isinstance(params, dict):
            for key, value in params.items():
                if isinstance(value, (list, tuple)):
                    for v in value:
                        self._store.append((str(key), primitive_value_to_str(v)))
                else:
                    self._store.append((str(key), primitive_value_to_str(value)))
        elif isinstance(params, list):
            for key, value in params:
                self._store.append((str(key), primitive_value_to_str(value)))
        else:
            raise TypeError("Unsupported params type for QueryParams")

    def __getitem__(self, name: str) -> typing.List[str]:
        """
        Return a list of values for the given parameter name.

        Raises KeyError if the name is not present.
        """
        values = [v for k, v in self._store if k == name]
        if not values:
            raise KeyError(name)
        return values

    def getlist(self, name: str) -> typing.List[str]:
        """
        Return a list of values for the given parameter name, or empty list.
        """
        return [v for k, v in self._store if k == name]

    def __contains__(self, name: str) -> bool:
        """
        Return True if the parameter name exists in the query parameters.
        """
        return any(k == name for k, _ in self._store)

    def __iter__(self) -> typing.Iterator[typing.Tuple[str, str]]:
        """
        Iterate over (key, value) pairs preserving order and duplicates.
        """
        return iter(list(self._store))

    def __len__(self) -> int:
        """
        Return the number of parameter pairs (counting duplicates).
        """
        return len(self._store)

    def __bool__(self) -> bool:
        """
        Truthiness of QueryParams: True if any parameters are present.
        """
        return bool(self._store)

    def __hash__(self) -> int:
        """
        Compute a hash based on the tuple of stored pairs.
        """
        return hash(tuple(self._store))

    def __eq__(self, other: typing.Any) -> bool:
        """
        Compare for equality with another QueryParams or compatible sequence.

        Two QueryParams are equal if their stored (key, value) sequences are equal.
        """
        if isinstance(other, QueryParams):
            return self._store == other._store
        if isinstance(other, list):
            return self._store == other
        return False

    def __repr__(self) -> str:
        """
        Return an unambiguous representation of the QueryParams.
        """
        return f"QueryParams({self._store!r})"

    def update(self, params: QueryParamTypes) -> None:
        """
        Update the query parameters by replacing all parameters with those provided.

        If provided a mapping, it will replace entries for the given keys.
        If provided a sequence of pairs, those pairs will be appended.
        """
        if isinstance(params, dict):
            # Remove existing keys present in params, then add new ones.
            keys = set(str(k) for k in params.keys())
            self._store = [(k, v) for (k, v) in self._store if k not in keys]
            for key, value in params.items():
                if isinstance(value, (list, tuple)):
                    for v in value:
                        self._store.append((str(key), primitive_value_to_str(v)))
                else:
                    self._store.append((str(key), primitive_value_to_str(value)))
        elif isinstance(params, str):
            other = QueryParams(params)
            self._store.extend(other._store)
        elif isinstance(params, list):
            for key, value in params:
                self._store.append((str(key), primitive_value_to_str(value)))
        else:
            raise TypeError("Unsupported params type for update")

    def __setitem__(self, name: str, value: typing.Any) -> None:
        """
        Set a parameter name to a single value, removing any existing values.

        Use a list or tuple to set multiple values for the same key.
        """
        # Remove existing entries
        self._store = [(k, v) for (k, v) in self._store if k != name]
        if isinstance(value, (list, tuple)):
            for v in value:
                self._store.append((name, primitive_value_to_str(v)))
        else:
            self._store.append((name, primitive_value_to_str(value)))

    def add(self, name: str, value: typing.Any) -> None:
        """
        Add an additional value for an existing parameter name (without removing).
        """
        self._store.append((name, primitive_value_to_str(value)))

    def remove(self, name: str) -> None:
        """
        Remove all entries for the given parameter name.
        """
        self._store = [(k, v) for (k, v) in self._store if k != name]

    def to_query_bytes(self) -> bytes:
        """
        Render the query parameters to a percent-encoded query bytes (without leading '?').
        """
        # build a list suitable for urlencode with doseq=True
        mapping: typing.Dict[str, typing.List[str]] = {}
        for k, v in self._store:
            mapping.setdefault(k, []).append(v)
        return _urlencode(mapping, doseq=True).encode("utf-8")


class URL:
    """
    A compact URL representation with basic parsing and query parameter helpers.

    This is a simplified version intended to support basic URL operations
    needed by tests that check for presence of docstrings and basic behavior.
    """

    DEFAULT_PORTS = {"http": 80, "https": 443, "ws": 80, "wss": 443, "ftp": 21}

    def __init__(self, url: URLTypes = "", **kwargs: typing.Any) -> None:
        """
        Initialize a URL instance.

        Accepts either another URL instance or a string. Keyword arguments allow
        overriding specific components (scheme, username, password, host, port,
        path, query, fragment, params).
        """
        # Start with defaults
        self.scheme: str = ""
        self.username: typing.Optional[str] = None
        self.password: typing.Optional[str] = None
        self.userinfo: typing.Optional[bytes] = None
        self.host: typing.Optional[str] = None
        self.raw_host: typing.Optional[bytes] = None
        self.port: typing.Optional[int] = None
        self.netloc: Optional[bytes] = None  # type: ignore[name-defined]
        self.path: str = ""
        self.query: bytes = b""
        self.raw_path: bytes = b""
        self.fragment: str = ""
        self.params: QueryParams = QueryParams()

        # If given a URL instance, copy attributes.
        if isinstance(url, URL):
            other = url
            self.scheme = other.scheme
            self.username = other.username
            self.password = other.password
            self.userinfo = other.userinfo
            self.host = other.host
            self.raw_host = other.raw_host
            self.port = other.port
            self.netloc = other.netloc
            self.path = other.path
            self.query = other.query
            self.raw_path = other.raw_path
            self.fragment = other.fragment
            self.params = QueryParams(list(other.params._store))
            # Apply any overrides
            for key, value in kwargs.items():
                setattr(self, key, value)
            return

        # Parse string URLs
        if isinstance(url, str):
            parsed = _urlparse(url)
            self.scheme = (parsed.scheme or "").lower()
            # netloc may contain username:password@host:port
            if parsed.username:
                self.username = unquote(parsed.username)
            if parsed.password:
                self.password = unquote(parsed.password)
            if parsed.hostname:
                # host is unicode, raw_host is IDNA-encoded bytes
                self.host = parsed.hostname.lower()
                try:
                    self.raw_host = idna.encode(self.host)
                except Exception:
                    # Fallback: encode bytes of the hostname as-is
                    self.raw_host = self.host.encode("utf-8")
            if parsed.port:
                self.port = parsed.port
                # Normalize default ports to None
                if self.scheme in self.DEFAULT_PORTS and self.port == self.DEFAULT_PORTS[self.scheme]:
                    self.port = None
            # Construct netloc as raw_host[:port]
            if self.raw_host is not None:
                if self.port is not None:
                    self.netloc = self.raw_host + b":" + str(self.port).encode("ascii")
                else:
                    self.netloc = self.raw_host
            # path and query handling
            self.path = unquote(parsed.path or "")
            # raw_path should include the query portion as bytes (without leading '?')
            raw_path = (parsed.path or "") + (("?" + parsed.query) if parsed.query else "")
            self.raw_path = raw_path.encode("utf-8")
            self.query = (parsed.query or "").encode("utf-8")
            self.fragment = parsed.fragment or ""
            # Parse params into QueryParams
            if parsed.query:
                self.params = QueryParams(parsed.query)
            # Apply any overrides
            for key, value in kwargs.items():
                setattr(self, key, value)
            return

        raise TypeError("URL must be constructed from a string or another URL instance")

    def copy_set_param(self, name: str, value: typing.Any) -> "URL":
        """
        Return a copy of this URL with the given query parameter name set to value.

        This replaces any existing values for the parameter with the provided one.
        """
        new_url = URL(self)
        new_url.params = QueryParams(list(self.params._store))
        new_url.params[name] = value
        # update raw query bytes
        new_url.query = new_url.params.to_query_bytes()
        new_url.raw_path = (new_url.path + (("?" + new_url.query.decode("utf-8")) if new_url.query else "")).encode("utf-8")
        return new_url

    def copy_add_param(self, name: str, value: typing.Any) -> "URL":
        """
        Return a copy of this URL with an additional value appended for the named parameter.

        If the parameter already exists, the new value is appended; otherwise the parameter is added.
        """
        new_url = URL(self)
        new_url.params = QueryParams(list(self.params._store))
        new_url.params.add(name, value)
        new_url.query = new_url.params.to_query_bytes()
        new_url.raw_path = (new_url.path + (("?" + new_url.query.decode("utf-8")) if new_url.query else "")).encode("utf-8")
        return new_url

    def copy_remove_param(self, name: str) -> "URL":
        """
        Return a copy of this URL with all values of the named parameter removed.
        """
        new_url = URL(self)
        new_url.params = QueryParams(list(self.params._store))
        new_url.params.remove(name)
        new_url.query = new_url.params.to_query_bytes()
        new_url.raw_path = (new_url.path + (("?" + new_url.query.decode("utf-8")) if new_url.query else "")).encode("utf-8")
        return new_url

    def copy_merge_params(self, params: QueryParamTypes) -> "URL":
        """
        Return a copy of this URL with its query parameters merged with the provided ones.

        The merge behavior:
        - dict: replace values for keys provided, preserving other keys
        - list of pairs: append the pairs to the existing parameters
        - string: parse as a query string and append its parameters
        """
        new_url = URL(self)
        new_url.params = QueryParams(list(self.params._store))
        new_url.params.update(params)
        new_url.query = new_url.params.to_query_bytes()
        new_url.raw_path = (new_url.path + (("?" + new_url.query.decode("utf-8")) if new_url.query else "")).encode("utf-8")
        return new_url

    def __hash__(self) -> int:
        """
        Compute a hash for the URL based on its canonical components.

        This includes scheme, userinfo, raw host, port, raw_path, and fragment.
        """
        return hash((self.scheme, self.userinfo, self.raw_host, self.port, self.raw_path, self.fragment))

    def __eq__(self, other: typing.Any) -> bool:
        """
        Compare two URLs for equality by comparing their canonical components.
        """
        if not isinstance(other, URL):
            return NotImplemented
        return (
            self.scheme == other.scheme
            and self.userinfo == other.userinfo
            and self.raw_host == other.raw_host
            and self.port == other.port
            and self.raw_path == other.raw_path
            and self.fragment == other.fragment
        )

    def __str__(self) -> str:
        """
        Return a human-readable string representation of the URL.
        """
        netloc = ""
        if self.username:
            netloc += self.username
            if self.password:
                netloc += ":" + self.password
            netloc += "@"
        if self.host:
            netloc += self.host
        if self.port is not None:
            netloc += f":{self.port}"
        path = self.path or ""
        query = ("?" + self.query.decode("utf-8")) if self.query else ""
        frag = ("#" + self.fragment) if self.fragment else ""
        return f"{self.scheme}://{netloc}{path}{query}{frag}"

    def __repr__(self) -> str:
        """
        Return an unambiguous representation of the URL suitable for debugging.
        """
        return f"URL({str(self)!r})"